class Solution:
    def isSubsequence(self, s: str, t: str) -> bool:
        if s == "": return True
        sPointer = 0

        for i in range(1+len(t)-len(s)):
            if (s[sPointer] == t[i]):
                
                sPointer += 1
                for j in range(i+1, len(t)):
                    if (sPointer == len(s)):
                        return True

                    if t[j] == s[sPointer]:
                        sPointer += 1
                
                if (sPointer == len(s)):
                    return True
                
                sPointer = 0
            i += 1
        return False
                    
s = Solution()
print(s.isSubsequence("bcd", ""))